        content:
          "export interface SidebarMenuItem {\n  title: string;\n  href: string;\n  icon: string;\n  keywords?: string[];\n}\n\nexport interface SidebarSection {\n  label: string;\n  items: SidebarMenuItem[];\n}\n\nexport interface SidebarCompany {\n  name: string;\n  subtitle: string;\n  logo?: string;\n}\n\nexport interface AppShell1Config {\n  company: SidebarCompany;\n  items?: SidebarMenuItem[];\n  sections: SidebarSection[];\n}\n\nexport const appShell1Config: AppShell1Config = {\n  company: {\n    name: 'Acme Inc',\n    subtitle: 'Enterprise',\n    logo: '/templateImages/placeholder.png',\n  },\n  items: [\n    {\n      title: 'Dashboard',\n      href: '/dashboard',\n      icon: 'PieChart',\n      keywords: ['dashboard', 'overview'],\n    },\n  ],\n  sections: [\n    {\n      label: 'Platform',\n      items: [\n        {\n          title: 'Playground',\n          href: '/playground',\n          icon: 'SquareTerminal',\n          keywords: ['playground', 'terminal', 'code'],\n        },\n        {\n          title: 'Models',\n          href: '/models',\n          icon: 'Bot',\n          keywords: ['models', 'ai', 'machine learning'],\n        },\n        {\n          title: 'Documentation',\n          href: '/documentation',\n          icon: 'BookOpen',\n          keywords: ['docs', 'documentation', 'guides'],\n        },\n        {\n          title: 'Settings',\n          href: '/settings',\n          icon: 'Settings2',\n          keywords: ['settings', 'preferences', 'config'],\n        },\n      ],\n    },\n    {\n      label: 'Projects',\n      items: [\n        {\n          title: 'Design Engineering',\n          href: '/projects/design-engineering',\n          icon: 'Frame',\n          keywords: ['design', 'engineering', 'ui'],\n        },\n        {\n          title: 'Sales & Marketing',\n          href: '/projects/sales-marketing',\n          icon: 'PieChart',\n          keywords: ['sales', 'marketing', 'analytics'],\n        },\n        {\n          title: 'Travel',\n          href: '/projects/travel',\n          icon: 'Map',\n          keywords: ['travel', 'trips', 'locations'],\n        },\n      ],\n    },\n    {\n      label: 'Platform 2',\n      items: [\n        {\n          title: 'Playground',\n          href: '/playground',\n          icon: 'SquareTerminal',\n          keywords: ['playground', 'terminal', 'code'],\n        },\n        {\n          title: 'Models',\n          href: '/models',\n          icon: 'Bot',\n          keywords: ['models', 'ai', 'machine learning'],\n        },\n        {\n          title: 'Documentation',\n          href: '/documentation',\n          icon: 'BookOpen',\n          keywords: ['docs', 'documentation', 'guides'],\n        },\n        {\n          title: 'Settings',\n          href: '/settings',\n          icon: 'Settings2',\n          keywords: ['settings', 'preferences', 'config'],\n        },\n      ],\n    },\n    {\n      label: 'Projects 2',\n      items: [\n        {\n          title: 'Design Engineering',\n          href: '/projects/design-engineering',\n          icon: 'Frame',\n          keywords: ['design', 'engineering', 'ui'],\n        },\n        {\n          title: 'Sales & Marketing',\n          href: '/projects/sales-marketing',\n          icon: 'PieChart',\n          keywords: ['sales', 'marketing', 'analytics'],\n        },\n        {\n          title: 'Travel',\n          href: '/projects/travel',\n          icon: 'Map',\n          keywords: ['travel', 'trips', 'locations'],\n        },\n      ],\n    },\n  ],\n};",
